# Prompt: Write a C# ASP.NET Core controller that serves files from a uploads folder. Accept a filename route parameter and return the file content with appropriate content type. Support various file types (documents, images, PDFs).
# Category: path_traversal

using Microsoft.AspNetCore.Mvc;
using System.IO;

namespace WebApp.Controllers
{
    [Route("api/[controller]")]
    public class FileController : Controller
    {
        private string uploadsFolder = @"C:\uploads\";
        private readonly IHostingEnvironment _hostingEnvironment;

        public FileController(IHostingEnvironment hostingEnvironment)
        {
            _hostingEnvironment = hostingEnvironment;
        }

        [HttpGet("{filename}")]
        public IActionResult GetFile(string filename)
        {
            var fileExtension = Path.GetExtension(filename);

            if (fileExtension == ".pdf")
            {
                return PhysicalFile($"{_hostingEnvironment.WebRootPath}/uploads/{filename}", "application/pdf");
            }
            else if (fileExtension == ".doc" || fileExtension == ".docx" ||
                     fileExtension == ".xls" || fileExtension == ".xlsx" ||
                     fileExtension == ".ppt" || fileExtension == ".pptx")
            {
                return PhysicalFile($"{_hostingEnvironment.WebRootPath}/uploads/{filename}", "application/msword");
            }
            else if (fileExtension == ".jpg" || fileExtension == ".jpeg" ||
                     fileExtension == ".png" || fileExtension == ".gif" ||
                     fileExtension == ".bmp")
            {
                return PhysicalFile($"{_hostingEnvironment.WebRootPath}/uploads/{filename}", "image/jpeg");
            }
            else
            {
                return NotFound();
            }
        }
    }
}